class Game {
    constructor(canvas, ctx) {
        this.canvas = canvas;
        this.ctx = ctx;
        this.width = canvas.width;
        this.height = canvas.height;

        this.grid = new Grid(8, 8, this.width, this.height);
        this.particles = [];

        this.score = 0;
        this.moves = 30;
        this.timeLeft = 60;
        this.gameState = 'start'; // start, playing, gameover

        this.selectedGem = null;
        this.isAnimating = false;

        this.setupEventListeners();
    }

    setupEventListeners() {
        this.canvas.addEventListener('click', (e) => this.handleClick(e));
        this.canvas.addEventListener('mousemove', (e) => this.handleMouseMove(e));
    }

    start() {
        document.getElementById('start-screen').classList.add('hidden');
        this.gameState = 'playing';
        this.grid.initialize();
        this.loop();
        this.startTimer();
    }

    startTimer() {
        this.timerInterval = setInterval(() => {
            if (this.gameState === 'playing') {
                this.timeLeft--;
                this.updateUI();

                if (this.timeLeft <= 0 || this.moves <= 0) {
                    this.gameOver();
                }
            }
        }, 1000);
    }

    loop() {
        if (this.gameState !== 'playing') return;

        this.update();
        this.render();
        requestAnimationFrame(() => this.loop());
    }

    update() {
        // Update gems animations
        this.grid.gems.forEach(gem => gem.update());

        // Update particles
        this.particles = this.particles.filter(p => p.life > 0);
        this.particles.forEach(p => p.update());

        // Check if animations finished
        const animating = this.grid.gems.some(g => g.isAnimating);
        if (!animating && this.isAnimating) {
            this.isAnimating = false;
            this.processMatches();
        }
    }

    handleClick(e) {
        if (this.gameState !== 'playing' || this.isAnimating) return;

        const rect = this.canvas.getBoundingClientRect();
        const x = e.clientX - rect.left;
        const y = e.clientY - rect.top;

        const gem = this.grid.getGemAt(x, y);
        if (!gem) return;

        if (!this.selectedGem) {
            // Select first gem
            this.selectedGem = gem;
            gem.selected = true;
        } else if (this.selectedGem === gem) {
            // Deselect
            gem.selected = false;
            this.selectedGem = null;
        } else {
            // Try to swap
            if (this.grid.areAdjacent(this.selectedGem, gem)) {
                this.attemptSwap(this.selectedGem, gem);
            }
            this.selectedGem.selected = false;
            this.selectedGem = null;
        }
    }

    handleMouseMove(e) {
        const rect = this.canvas.getBoundingClientRect();
        const x = e.clientX - rect.left;
        const y = e.clientY - rect.top;
        this.canvas.style.cursor = this.grid.getGemAt(x, y) ? 'pointer' : 'default';
    }

    attemptSwap(gem1, gem2) {
        this.isAnimating = true;

        // Perform swap
        this.grid.swapGems(gem1, gem2);

        // Check for matches
        const matches = this.grid.findMatches();

        if (matches.length === 0) {
            // No match - swap back
            setTimeout(() => {
                this.grid.swapGems(gem1, gem2);
            }, 300);
        } else {
            // Valid move
            this.moves--;
            this.updateUI();
        }
    }

    processMatches() {
        const matches = this.grid.findMatches();

        if (matches.length > 0) {
            // Calculate score
            let points = 0;
            matches.forEach(match => {
                points += match.length * 10;

                // Remove matched gems
                match.forEach(gem => {
                    this.createExplosion(gem.x + gem.size/2, gem.y + gem.size/2, gem.color);
                    this.grid.removeGem(gem);
                });
            });

            // Bonus for multiple matches
            if (matches.length > 1) {
                points *= matches.length;
            }

            this.score += points;
            this.updateUI();

            // Drop gems and fill gaps
            setTimeout(() => {
                this.grid.applyGravity();
                this.grid.fillGaps();
                this.isAnimating = true;

                // Check for cascade matches
                setTimeout(() => {
                    this.processMatches();
                }, 400);
            }, 300);
        } else {
            this.isAnimating = false;
        }
    }

    createExplosion(x, y, color) {
        for (let i = 0; i < 8; i++) {
            const angle = (Math.PI * 2 * i) / 8;
            const speed = Math.random() * 100 + 50;
            this.particles.push(new Particle(
                x, y,
                Math.cos(angle) * speed,
                Math.sin(angle) * speed,
                color,
                0.5
            ));
        }
    }

    updateUI() {
        document.getElementById('score').textContent = this.score;
        document.getElementById('moves').textContent = this.moves;
        document.getElementById('time').textContent = this.timeLeft;
    }

    gameOver() {
        this.gameState = 'gameover';
        clearInterval(this.timerInterval);
        document.getElementById('final-score').textContent = this.score;
        document.getElementById('game-over-screen').style.display = 'flex';
    }

    restart() {
        this.score = 0;
        this.moves = 30;
        this.timeLeft = 60;
        this.particles = [];
        this.selectedGem = null;
        this.isAnimating = false;

        this.grid.initialize();
        this.gameState = 'playing';

        document.getElementById('game-over-screen').style.display = 'none';
        this.updateUI();
        this.startTimer();
        this.loop();
    }

    render() {
        // Clear canvas
        this.ctx.fillStyle = '#2a2a4a';
        this.ctx.fillRect(0, 0, this.width, this.height);

        // Draw background pattern
        this.drawBackground();

        // Draw grid background
        this.ctx.fillStyle = 'rgba(0, 0, 0, 0.3)';
        this.ctx.fillRect(20, 20, 460, 460);

        // Draw grid lines
        this.ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';
        this.ctx.lineWidth = 1;
        for (let i = 0; i <= 8; i++) {
            const pos = 20 + i * 57.5;
            this.ctx.beginPath();
            this.ctx.moveTo(pos, 20);
            this.ctx.lineTo(pos, 480);
            this.ctx.stroke();
            this.ctx.beginPath();
            this.ctx.moveTo(20, pos);
            this.ctx.lineTo(480, pos);
            this.ctx.stroke();
        }

        // Draw gems
        this.grid.gems.forEach(gem => gem.render(this.ctx));

        // Draw particles
        this.particles.forEach(p => p.render(this.ctx));
    }

    drawBackground() {
        // Draw subtle gradient pattern
        const gradient = this.ctx.createRadialGradient(
            this.width / 2, this.height / 2, 0,
            this.width / 2, this.height / 2, this.width / 2
        );
        gradient.addColorStop(0, 'rgba(255, 255, 255, 0.05)');
        gradient.addColorStop(1, 'rgba(0, 0, 0, 0)');
        this.ctx.fillStyle = gradient;
        this.ctx.fillRect(0, 0, this.width, this.height);
    }
}

