class Gem {
    constructor(row, col, type, size) {
        this.row = row;
        this.col = col;
        this.type = type;
        this.size = size;
        this.padding = 5;

        // Calculate position
        this.x = 20 + col * size;
        this.y = 20 + row * size;
        this.targetX = this.x;
        this.targetY = this.y;

        // Gem properties based on type
        const colors = [
            '#ff6b6b', // Red
            '#4ecdc4', // Teal
            '#ffe66d', // Yellow
            '#95e1d3', // Mint
            '#f38181', // Pink
            '#aa96da'  // Purple
        ];
        const shapes = ['circle', 'square', 'diamond', 'triangle', 'hexagon', 'star'];

        this.color = colors[type % colors.length];
        this.shape = shapes[type % shapes.length];
        this.selected = false;
        this.isAnimating = false;
        this.scale = 1;
        this.matched = false;
    }

    update() {
        // Smooth animation to target position
        const dx = this.targetX - this.x;
        const dy = this.targetY - this.y;

        if (Math.abs(dx) > 0.5 || Math.abs(dy) > 0.5) {
            this.x += dx * 0.2;
            this.y += dy * 0.2;
            this.isAnimating = true;
        } else {
            this.x = this.targetX;
            this.y = this.targetY;
            this.isAnimating = false;
        }

        // Selection pulse animation
        if (this.selected) {
            this.scale = 1 + Math.sin(Date.now() / 200) * 0.1;
        } else {
            this.scale = 1;
        }

        // Match shrink animation
        if (this.matched) {
            this.scale *= 0.9;
        }
    }

    render(ctx) {
        if (this.scale <= 0.01) return;

        ctx.save();
        ctx.translate(this.x + this.size / 2, this.y + this.size / 2);
        ctx.scale(this.scale, this.scale);
        ctx.translate(-this.size / 2, -this.size / 2);

        // Draw selection highlight
        if (this.selected) {
            ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
            ctx.fillRect(-5, -5, this.size + 10, this.size + 10);
        }

        // Draw gem shadow
        ctx.fillStyle = 'rgba(0, 0, 0, 0.3)';
        this.drawShape(ctx, 3, 3);

        // Draw gem
        ctx.fillStyle = this.color;
        this.drawShape(ctx, 0, 0);

        // Draw highlight
        ctx.fillStyle = 'rgba(255, 255, 255, 0.4)';
        this.drawHighlight(ctx);

        ctx.restore();
    }

    drawShape(ctx, offsetX, offsetY) {
        const x = this.padding + offsetX;
        const y = this.padding + offsetY;
        const w = this.size - this.padding * 2;
        const h = this.size - this.padding * 2;
        const cx = x + w / 2;
        const cy = y + h / 2;

        ctx.beginPath();

        switch(this.shape) {
            case 'circle':
                ctx.arc(cx, cy, w / 2, 0, Math.PI * 2);
                break;
            case 'square':
                ctx.roundRect(x, y, w, h, 8);
                break;
            case 'diamond':
                ctx.moveTo(cx, y);
                ctx.lineTo(x + w, cy);
                ctx.lineTo(cx, y + h);
                ctx.lineTo(x, cy);
                ctx.closePath();
                break;
            case 'triangle':
                ctx.moveTo(cx, y);
                ctx.lineTo(x + w, y + h);
                ctx.lineTo(x, y + h);
                ctx.closePath();
                break;
            case 'hexagon':
                for (let i = 0; i < 6; i++) {
                    const angle = (Math.PI / 3) * i;
                    const px = cx + Math.cos(angle) * w / 2;
                    const py = cy + Math.sin(angle) * h / 2;
                    if (i === 0) ctx.moveTo(px, py);
                    else ctx.lineTo(px, py);
                }
                ctx.closePath();
                break;
            case 'star':
                for (let i = 0; i < 10; i++) {
                    const angle = (Math.PI / 5) * i - Math.PI / 2;
                    const radius = i % 2 === 0 ? w / 2 : w / 4;
                    const px = cx + Math.cos(angle) * radius;
                    const py = cy + Math.sin(angle) * radius;
                    if (i === 0) ctx.moveTo(px, py);
                    else ctx.lineTo(px, py);
                }
                ctx.closePath();
                break;
        }

        ctx.fill();
    }

    drawHighlight(ctx) {
        const cx = this.size / 2;
        const cy = this.size / 2;
        const r = this.size / 6;
        ctx.beginPath();
        ctx.arc(cx - r/2, cy - r/2, r, 0, Math.PI * 2);
        ctx.fill();
    }
}

