class Grid {
    constructor(rows, cols, canvasWidth, canvasHeight) {
        this.rows = rows;
        this.cols = cols;
        this.gems = [];
        this.cellSize = 57.5;
    }

    initialize() {
        this.gems = [];
        for (let row = 0; row < this.rows; row++) {
            for (let col = 0; col < this.cols; col++) {
                const type = Math.floor(Math.random() * 6);
                this.gems.push(new Gem(row, col, type, this.cellSize));
            }
        }

        // Remove initial matches
        while (this.findMatches().length > 0) {
            this.shuffle();
        }
    }

    shuffle() {
        this.gems.forEach(gem => {
            gem.type = Math.floor(Math.random() * 6);
        });
    }

    getGemAt(x, y) {
        const col = Math.floor((x - 20) / this.cellSize);
        const row = Math.floor((y - 20) / this.cellSize);
        return this.getGem(row, col);
    }

    getGem(row, col) {
        if (row < 0 || row >= this.rows || col < 0 || col >= this.cols) {
            return null;
        }
        return this.gems.find(g => g.row === row && g.col === col);
    }

    areAdjacent(gem1, gem2) {
        const rowDiff = Math.abs(gem1.row - gem2.row);
        const colDiff = Math.abs(gem1.col - gem2.col);
        return (rowDiff === 1 && colDiff === 0) || (rowDiff === 0 && colDiff === 1);
    }

    swapGems(gem1, gem2) {
        // Swap types
        const tempType = gem1.type;
        gem1.type = gem2.type;
        gem2.type = tempType;

        // Swap shapes
        const tempShape = gem1.shape;
        gem1.shape = gem2.shape;
        gem2.shape = tempShape;

        // Swap colors
        const tempColor = gem1.color;
        gem1.color = gem2.color;
        gem2.color = tempColor;
    }

    findMatches() {
        const matches = [];
        const matched = new Set();

        // Check horizontal matches
        for (let row = 0; row < this.rows; row++) {
            let count = 1;
            let currentType = this.getGem(row, 0).type;

            for (let col = 1; col < this.cols; col++) {
                const gem = this.getGem(row, col);
                if (gem.type === currentType) {
                    count++;
                } else {
                    if (count >= 3) {
                        const match = [];
                        for (let i = col - count; i < col; i++) {
                            const g = this.getGem(row, i);
                            if (!matched.has(g)) {
                                match.push(g);
                                matched.add(g);
                            }
                        }
                        if (match.length >= 3) matches.push(match);
                    }
                    count = 1;
                    currentType = gem.type;
                }
            }

            if (count >= 3) {
                const match = [];
                for (let i = this.cols - count; i < this.cols; i++) {
                    const g = this.getGem(row, i);
                    if (!matched.has(g)) {
                        match.push(g);
                        matched.add(g);
                    }
                }
                if (match.length >= 3) matches.push(match);
            }
        }

        // Check vertical matches
        for (let col = 0; col < this.cols; col++) {
            let count = 1;
            let currentType = this.getGem(0, col).type;

            for (let row = 1; row < this.rows; row++) {
                const gem = this.getGem(row, col);
                if (gem.type === currentType) {
                    count++;
                } else {
                    if (count >= 3) {
                        const match = [];
                        for (let i = row - count; i < row; i++) {
                            const g = this.getGem(i, col);
                            if (!matched.has(g)) {
                                match.push(g);
                                matched.add(g);
                            }
                        }
                        if (match.length >= 3) matches.push(match);
                    }
                    count = 1;
                    currentType = gem.type;
                }
            }

            if (count >= 3) {
                const match = [];
                for (let i = this.rows - count; i < this.rows; i++) {
                    const g = this.getGem(i, col);
                    if (!matched.has(g)) {
                        match.push(g);
                        matched.add(g);
                    }
                }
                if (match.length >= 3) matches.push(match);
            }
        }

        return matches;
    }

    removeGem(gem) {
        gem.matched = true;
    }

    applyGravity() {
        for (let col = 0; col < this.cols; col++) {
            let writeRow = this.rows - 1;

            for (let row = this.rows - 1; row >= 0; row--) {
                const gem = this.getGem(row, col);
                if (!gem.matched) {
                    if (writeRow !== row) {
                        // Move gem down
                        const targetGem = this.getGem(writeRow, col);
                        targetGem.type = gem.type;
                        targetGem.shape = gem.shape;
                        targetGem.color = gem.color;
                        targetGem.targetY = 20 + writeRow * this.cellSize;
                        targetGem.isAnimating = true;
                        gem.matched = true;
                    }
                    writeRow--;
                }
            }
        }
    }

    fillGaps() {
        for (let col = 0; col < this.cols; col++) {
            for (let row = 0; row < this.rows; row++) {
                const gem = this.getGem(row, col);
                if (gem.matched) {
                    // Assign new random type
                    gem.type = Math.floor(Math.random() * 6);
                    const colors = ['#ff6b6b', '#4ecdc4', '#ffe66d', '#95e1d3', '#f38181', '#aa96da'];
                    const shapes = ['circle', 'square', 'diamond', 'triangle', 'hexagon', 'star'];
                    gem.color = colors[gem.type];
                    gem.shape = shapes[gem.type];
                    gem.matched = false;
                    gem.scale = 1;

                    // Animate from top
                    gem.y = 20 - (this.rows - row) * this.cellSize;
                    gem.targetY = 20 + row * this.cellSize;
                    gem.isAnimating = true;
                }
            }
        }
    }
}

